### Option 2: Interactive Browser Model (Three.js)
This is a complete, single-file HTML solution. You can save this code as an `.html` file (e.g., `house.html`) and open it in any modern web browser to see a fully rendered, rotatable 3D house.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: Arial, sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click and drag to rotate • Scroll to zoom</div>
    <!-- Load Three.js from CDN -->
    <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
    <script src="https://cdn.jsdelivr.net/npm/three@0.128.0/examples/js/controls/OrbitControls.js"></script>

    <script>
        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue

        // Camera
        const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 15, 20);

        // Renderer
        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // Controls
        const controls = new THREE.OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 2. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 0.8);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        scene.add(dirLight);

        // 3. Building the House
        const houseGroup = new THREE.Group();

        // Materials
        const wallMaterial = new THREE.MeshLambertMaterial({ color: 0xffffff });
        const roofMaterial = new THREE.MeshLambertMaterial({ color: 0x8B4513 });
        const windowMaterial = new THREE.MeshBasicMaterial({ color: 0x87CEEB });

        // Base Geometry
        const baseGeo = new THREE.BoxGeometry(10, 6, 10);
        const base = new THREE.Mesh(baseGeo, wallMaterial);
        base.position.y = 3;
        base.castShadow = true;
        base.receiveShadow = true;
        houseGroup.add(base);

        // Roof Geometry (Pyramid)
        const roofGeo = new THREE.ConeGeometry(8, 6, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 9;
        roof.rotation.y = Math.PI / 4; // Rotate to align with base
        roof.castShadow = true;
        houseGroup.add(roof);

        // Windows
        function createWindow(x, z, y, w, h) {
            const winGeo = new THREE.PlaneGeometry(w, h);
            const win = new THREE.Mesh(winGeo, windowMaterial);
            win.position.set(x, y, z);
            win.lookAt(0, y, 0); // Face center
            houseGroup.add(win);
        }

        createWindow(2, 2, 2.5, 2, 3);
        createWindow(-2, 2, 2.5, 2, 3);
        createWindow(2, -2, 2.5, 2, 3);
        createWindow(-2, -2, 2.5, 2, 3);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 4, 0.2);
        const doorMat = new THREE.MeshLambertMaterial({ color: 0x8B0000 });
        const door = new THREE.Mesh(doorGeo, doorMat);
        door.position.set(0, 2, 5.1);
        houseGroup.add(door);

        scene.add(houseGroup);

        // 4. Ground
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const groundMat = new THREE.MeshLambertMaterial({ color: 0x228B22 });
        const ground = new THREE.Mesh(groundGeo, groundMat);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // 5. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use the HTML version:
1.  Copy the code block above.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in your web browser. You can rotate the camera with your mouse.
